module register_32bit
    (
        input rst_n,
        input clk,
        input load,
        input [31:0] data_in,
        output reg [31:0] data_out
    );

    reg [31:0] reg_data;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) 
    begin
        if (!rst_n)
            reg_data <= 32'd0;
        else if (load)
            reg_data <= data_in;
    end

    always @(posedge clk)
    begin
        data_out <= reg_data;
    end

endmodule
